using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Preserve the old discriminator JSON property name ("Discriminator" instead of "$type")
            b.HasDiscriminator<string>("Discriminator");
            // Preserve the old id format that includes the discriminator ("Blog|1" instead of "1")
            b.HasDiscriminatorInJsonId();
            // Preserve the old shadow __id property for the Cosmos resource id
            b.HasShadowId();
        });
        // Removed: HasIndex is no longer silently ignored; Cosmos indexes all properties by default
    }
}
